import React, { useEffect, useState } from 'react';
import api from '../api';
import { Appointment, Patient, Doctor } from '../types';

const AppointmentList: React.FC = () => {
    const [appointments, setAppointments] = useState<Appointment[]>([]);
    const [patients, setPatients] = useState<Patient[]>([]);
    const [doctors, setDoctors] = useState<Doctor[]>([]);
    
    const [selectedPatient, setSelectedPatient] = useState(0);
    const [selectedDoctor, setSelectedDoctor] = useState(0);

    useEffect(() => {
        api.get('appointments/').then(res => setAppointments(res.data));
        api.get('patients/').then(res => setPatients(res.data));
        api.get('doctors/').then(res => setDoctors(res.data));
    }, []);

    const handleSchedule = async () => {
        const payload = {
            patient: selectedPatient, // ID number
            doctor: selectedDoctor,   // ID number
            appointment_date: new Date().toISOString(),
            status: "Scheduled"
        };
        await api.post('appointments/', payload);
        alert("Success!");
    };

    return (
        <div className="p-4 border">
            <h3>Scheduled Appointments</h3>
            <select onChange={e => setSelectedPatient(Number(e.target.value))}>
                <option>Select Patient</option>
                {patients.map(p => <option key={p.patient_id} value={p.patient_id}>{p.last_name}</option>)}
            </select>
            <select onChange={e => setSelectedDoctor(Number(e.target.value))}>
                <option>Select Doctor</option>
                {doctors.map(d => <option key={d.doctor_id} value={d.doctor_id}>{d.last_name}</option>)}
            </select>
            <button onClick={handleSchedule} className="bg-purple-500 text-white p-1">Schedule</button>
        </div>
    );
};
export default AppointmentList;
